export default class Emitter {
  constructor() {
    this.events = new Map();
  }

  on(event, listener) {
    if (!this.events.has(event)) this.events.set(event, []);
    this.events.get(event).push(listener);
  }

  off(event, listener) {
    const list = this.events.get(event);
    if (!list) return;
    this.events.set(event, list.filter(l => l !== listener));
  }

  emit(event, ...args) {
    const list = this.events.get(event);
    if (!list || list.length === 0) return;
    for (const l of list.slice()) l(...args);
  }
}
